//! Tauri IPC commands exposed to the frontend.
//!
//! Each `#[tauri::command]` function mirrors a typed contract in
//! `src/ipc/bindings.ts` (auto-generated by `tauri-specta`). The
//! commands are split into sub-modules by domain:
//!
//! - [`streaming`] â€” live transcription session lifecycle
//! - [`meetings`] â€” CRUD + search over persisted meetings
//! - [`llm`] â€” summary generation and transcript chat
//! - [`export`] â€” file export (Markdown / plain text)
//! - [`models`] â€” model catalog, status, and download

pub mod export;
pub mod hardware;
